SELECT set_name
FROM card_sets
WHERE sport = 'Basketball';

SELECT set_name, total_cards
FROM card_sets
ORDER BY total_cards DESC;

SELECT total_cards
FROM card_sets
WHERE set_id = 1;

SELECT COUNT(DISTINCT set_id) AS total_unique_sets
FROM card_sets
WHERE release_year = 2022;

SELECT set_name, total_cards
FROM card_sets
WHERE total_cards >= 100;
